//## Zustand/Jotai

//Lightweight state (alternatives to Redux).

// Zustand
const useStore = create((set) => ({
  count: 0, inc: () => set((state) => ({ count: state.count + 1 }))
}));
function Comp() { const { count, inc } = useStore(); return <button onClick={inc}>{count}</button>; }

//## Redux/RTK

//Centralized store for complex apps.

const counterSlice = createSlice({
  name: 'counter', initialState: { value: 0 },
  reducers: { increment: state => { state.value += 1; } }
});
const store = configureStore({ reducer: counterSlice.reducer });
<Provider store={store}><App /></Provider>

// ## Context API

// Global state without prop drilling.

const ThemeContext = createContext();
<ThemeContext.Provider value={{ dark: true }}>
  <Child />
</ThemeContext.Provider>
// Child: const theme = useContext(ThemeContext);

// ## Hooks (useState/useEffect)

// Functional state/logic without classes or HOCs.


function MyComponent() {
  const [count, setCount] = useState(0);
  useEffect(() => { /* fetch data */ }, []);
  return <button onClick={() => setCount(c => c+1)}>{count}</button>;
}

//## Render Props

//Shares code via a prop that renders content, avoiding HOC wrapper hell.

<DataProvider render={({ data }) => <MyComponent data={data} />} />

// ## Higher-Order Components (HOC)

// Wraps a component to reuse logic like data fetching or auth.[1]

const withAuth = (WrappedComponent) => {
  return (props) => (
    <AuthProvider>
      <WrappedComponent {...props} />
    </AuthProvider>
  );
};
const AuthApp = withAuth(MyComponent);
